{
  "name": "@belt/compliance",
  "version": "0.1.2",
  "description": "Be compliant!",
  "type": "module",
  "main": "dist/src/daemon.js",
  "types": "dist/src/daemon.d.ts",
  "bin": {
    "compliance": "./dist/src/cli.js"
  },
  "files": [
    "dist"
  ],
  "exports": {
    ".": {
      "types": "./dist/src/daemon.d.ts",
      "import": "./dist/src/daemon.js"
    },
    "./config": {
      "types": "./dist/src/config.d.ts",
      "import": "./dist/src/config.js"
    },
    "./stats": {
      "types": "./dist/src/stats.d.ts",
      "import": "./dist/src/stats.js"
    }
  },
  "scripts": {
    "dev": "bun run src/cli.ts",
    "build": "tsc",
    "start": "node dist/src/cli.js start",
    "test": "vitest run",
    "test:watch": "vitest",
    "check": "tsc --noEmit"
  },
  "keywords": [
    "teams",
    "presence",
    "status",
    "mouse",
    "jiggler",
    "activity",
    "cli"
  ],
  "author": "Antonio Presto <antoniopresto@gmail.com>",
  "license": "MIT",
  "repository": {
    "type": "git",
    "url": "https://github.com/antoniopresto/belt",
    "directory": "packages/compliance"
  },
  "dependencies": {
    "@jitsi/robotjs": "^0.6.11",
    "commander": "^12.0.0"
  },
  "devDependencies": {
    "@types/node": "^20.10.0",
    "typescript": "^5.9.3",
    "vitest": "^4.0.16"
  },
  "engines": {
    "node": ">=20.0.0"
  },
  "publishConfig": {
    "access": "public"
  }
}
